import{c as a,Q as i,j as n,m as t}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Designing Agentic Loops","description":"","frontmatter":{"title":"Designing Agentic Loops","author":"Simon Willison","date":"2025-09-30T00:00:00.000Z","source":"https://simonwillison.net/2025/Sep/30/designing-agentic-loops/","tags":["agent-harness","research"]},"headers":[],"relativePath":"research/agent-harness/references/2025-09-30-designing-agentic-loops-simon-willison.md","filePath":"research/agent-harness/references/2025-09-30-designing-agentic-loops-simon-willison.md","lastUpdated":1779894392000}'),s={name:"research/agent-harness/references/2025-09-30-designing-agentic-loops-simon-willison.md"};function o(r,e,l,c,d,g){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="designing-agentic-loops" tabindex="-1">Designing Agentic Loops <a class="header-anchor" href="#designing-agentic-loops" aria-label="Permalink to &quot;Designing Agentic Loops&quot;">​</a></h1><p>An agent is defined as something that &quot;runs tools in a loop to achieve a goal.&quot;</p><h2 id="yolo-mode-and-safety" tabindex="-1">YOLO Mode and Safety <a class="header-anchor" href="#yolo-mode-and-safety" aria-label="Permalink to &quot;YOLO Mode and Safety&quot;">​</a></h2><p>The tension between agent effectiveness and safety is critical. While approval-required modes are tedious, unrestricted operation risks data loss, system compromise, and exfiltration attacks.</p><p><strong>Recommendation</strong>: Run agents in isolated environments like GitHub Codespaces or Docker containers with restricted network access rather than on personal machines.</p><h2 id="tool-selection" tabindex="-1">Tool Selection <a class="header-anchor" href="#tool-selection" aria-label="Permalink to &quot;Tool Selection&quot;">​</a></h2><p>Rather than relying on Model Context Protocol (MCP), focus on shell commands and creating documentation files listing available tools. LLMs already understand many existing utilities like Playwright and FFmpeg.</p><h2 id="credential-management" tabindex="-1">Credential Management <a class="header-anchor" href="#credential-management" aria-label="Permalink to &quot;Credential Management&quot;">​</a></h2><p>When authentication is necessary:</p><ul><li>Provide access only to test environments</li><li>Implement strict budget limits on spending-capable credentials</li><li>Example: Create a dedicated Fly.io organization for a specific investigation</li></ul><h2 id="ideal-use-cases" tabindex="-1">Ideal Use Cases <a class="header-anchor" href="#ideal-use-cases" aria-label="Permalink to &quot;Ideal Use Cases&quot;">​</a></h2><p>Agentic loops work best for problems with clear success criteria requiring trial-and-error iteration:</p><ul><li>Debugging</li><li>Performance optimization</li><li>Dependency upgrades</li><li>Container optimization</li></ul><p>Strong automated test suites amplify agent effectiveness.</p><h2 id="emerging-skillset" tabindex="-1">Emerging Skillset <a class="header-anchor" href="#emerging-skillset" aria-label="Permalink to &quot;Emerging Skillset&quot;">​</a></h2><p>This represents an emerging skillset, with Claude Code&#39;s February 2025 release marking early adoption of agentic loop design patterns.</p>',16)])])}const h=a(s,[["render",o]]);export{m as __pageData,h as default};
